function FI({children,d=0}){
  const r=useRef(null);const[v,setV]=useState(false);
  useEffect(()=>{const el=r.current;if(!el)return;const ob=new IntersectionObserver(([e])=>{if(e.isIntersecting)setV(true)},{threshold:.06});ob.observe(el);return()=>ob.disconnect();},[]);
  return <div ref={r} style={{opacity:v?1:0,transform:v?"none":"translateY(28px)",transition:`opacity 1.6s ease ${d}s, transform 1.6s ease ${d}s`}}>{children}</div>;
}
